import scala.math.max

/**
 * A helper function to check if an index i is a peak in the circular array nums.
 * A peak is defined as nums[i] strictly greater than both its neighbors.
 *
 * @param nums The circular array.
 * @param i The index to check.
 * @return true if nums[i] is a peak, false otherwise.
 */
def isPeak(nums: Array[Long], i: Int): Boolean = {
  val n = nums.length
  // Get previous neighbor (circular)
  val prev = nums[(i - 1 + n) % n]
  // Get next neighbor (circular)
  val next = nums[(i + 1) % n]

  // Check if nums[i] is strictly greater than both neighbors
  nums(i) > prev && nums(i) > next
}

